/**
 * Run a backup for an external service manually.
 *
 * Enqueues the backup for asynchronous execution via the `BackupRunner`
 * (ADR-014). Returns `202 Accepted` immediately: pending parent and child
 * rows are inserted, and a `backup_jobs` row is enqueued for the resolved
 * engine. Poll `GET /backups/{id}` to observe `pending → running → completed`.
 */
export const runExternalServiceBackup = <ThrowOnError extends boolean = false>(options: Options<RunExternalServiceBackupData, ThrowOnError>): RequestResult<RunExternalServiceBackupResponses, RunExternalServiceBackupErrors, ThrowOnError> => (options.client ?? client).post<RunExternalServiceBackupResponses, RunExternalServiceBackupErrors, ThrowOnError>({
    security: [{ scheme: 'bearer', type: 'http' }],
    url: '/backups/external-services/{id}/run',
    ...options,
    headers: {
        'Content-Type': 'application/json',
        ...options.headers
    }
});

