/**
 * List a merged page of observability events for a project.
 *
 * Each row carries everything the side panel needs to render — no
 * follow-up fetch is required for the common case. Heavy fields
 * (stacktraces, headers, span attributes) are truncated server-side and
 * expose a `*_truncated` flag; clients fetch the full row from the
 * `/full` endpoint only when the user explicitly clicks "Show full".
 */
export const observabilityListEvents = <ThrowOnError extends boolean = false>(options: Options<ObservabilityListEventsData, ThrowOnError>): RequestResult<ObservabilityListEventsResponses, ObservabilityListEventsErrors, ThrowOnError> => (options.client ?? client).get<ObservabilityListEventsResponses, ObservabilityListEventsErrors, ThrowOnError>({
    security: [{ scheme: 'bearer', type: 'http' }],
    url: '/projects/{project_id}/observe/events',
    ...options
});

/**
 * Fetch the un-truncated form of one event by `(kind, id)`. Side panel
 * "Show full" action calls this — the list response carries truncated
 * previews + a `*_truncated` flag to let the UI decide whether to fetch.
 */
export const observabilityFullEvent = <ThrowOnError extends boolean = false>(options: Options<ObservabilityFullEventData, ThrowOnError>): RequestResult<ObservabilityFullEventResponses, ObservabilityFullEventErrors, ThrowOnError> => (options.client ?? client).get<ObservabilityFullEventResponses, ObservabilityFullEventErrors, ThrowOnError>({
    security: [{ scheme: 'bearer', type: 'http' }],
    url: '/projects/{project_id}/observe/events/{kind}/{event_id}/full',
    ...options
});

